changeSet.sql:
insert into RELATIONSHIP_LINK (ID, RELATIONSHIP_MODEL, CREATED_AT) select ID, RELATIONSHIP_MODEL, CREATED_AT from RELATIONSHIP_LINK_OLD;
insert into RELATIONSHIP_ROLE (RELATIONSHIP_ID, ROLE_NAME, ROLE_DOCREF) select l.ID, l.ENTITY_ROLE_1, d.MODEL_NAME || '/' || l.ENTITY_DOCREF_1 from RELATIONSHIP_LINK_OLD l, DOCUMENT d where l.ENTITY_DOCREF_1 = d.ID;
insert into RELATIONSHIP_ROLE (RELATIONSHIP_ID, ROLE_NAME, ROLE_DOCREF) select l.ID, l.ENTITY_ROLE_2, d.MODEL_NAME || '/' || l.ENTITY_DOCREF_2 from RELATIONSHIP_LINK_OLD l, DOCUMENT d where l.ENTITY_DOCREF_2 = d.ID;
insert into RELATIONSHIP_ORDER (ID, ROLE_ORDER) select e.ID, l.ORDER_1 from RELATIONSHIP_LINK_OLD l, RELATIONSHIP_ROLE e where l.ID = e.RELATIONSHIP_ID and l.ENTITY_ROLE_1 = e.ROLE_NAME and l.ENTITY_DOCREF_1 = e.ROLE_DOCREF;
insert into RELATIONSHIP_ORDER (ID, ROLE_ORDER) select e.ID, l.ORDER_2 from RELATIONSHIP_LINK_OLD l, RELATIONSHIP_ROLE e where l.ID = e.RELATIONSHIP_ID and l.ENTITY_ROLE_2 = e.ROLE_NAME and l.ENTITY_DOCREF_2 = e.ROLE_DOCREF;
